好的，这是一个完整的贪吃蛇游戏代码。你可以直接将其保存为一个 `.html` 文件（例如 `snake.html`），然后用浏览器（Chrome, Edge, Safari 等）打开即可游玩。

这个版本包含了：
1.  **HTML 结构**：画布和分数显示。
2.  **CSS 样式**：美化界面，使其居中显示。
3.  **JavaScript 逻辑**：核心游戏算法（移动、吃食物、碰撞检测）。

### 完整代码

```html
<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>贪吃蛇游戏</title>
    <style>
        body {
            display: flex;
            flex-direction: column;
            justify-content: center;
            align-items: center;
            height: 100vh;
            margin: 0;
            background-color: #2c3e50;
            font-family: 'Arial', sans-serif;
            color: white;
        }

        h1 {
            margin-top: 0;
        }

        #gameCanvas {
            border: 5px solid #ecf0f1;
            background-color: #34495e;
            box-shadow: 0 0 20px rgba(0,0,0,0.5);
        }

        #scoreBoard {
            font-size: 24px;
            margin-bottom: 10px;
        }

        .controls {
            margin-top: 15px;
            font-size: 14px;
            color: #bdc3c7;
        }
    </style>
</head>
<body>

    <h1>贪吃蛇</h1>
    <div id="scoreBoard">得分: <span id="score">0</span></div>
    <canvas id="gameCanvas" width="400" height="400"></canvas>
    <div class="controls">使用方向键 (↑ ↓ ← →) 控制移动</div>

    <script>
        // 获取画布和上下文
        const gameCanvas = document.getElementById("gameCanvas");
        const ctx = gameCanvas.getContext("2d");
        const scoreElement = document.getElementById("score");

        // 游戏常量
        const CANVAS_BORDER_COLOUR = 'black';
        const CANVAS_BACKGROUND_COLOUR = "#34495e";
        const SNAKE_COLOUR = '#2ecc71';
        const SNAKE_BORDER_COLOUR = '#27ae60';
        const FOOD_COLOUR = '#e74c3c';
        const FOOD_BORDER_COLOUR = '#c0392b';

        // 蛇的初始状态
        let snake = [
            {x: 200, y: 200},
            {x: 190, y: 200},
            {x: 180, y: 200},
            {x: 170, y: 200},
            {x: 160, y: 200}
        ];

        let score = 0;
        // 移动方向 (dx: 水平速度, dy: 垂直速度)
        let dx = 10;
        let dy = 0;

        // 食物坐标
        let foodX;
        let foodY;

        // 防止按键过快导致掉头自杀
        let changingDirection = false;

        // 开始游戏
        main();
        createFood();
        document.addEventListener("keydown", changeDirection);

        // 主游戏循环
        function main() {
            if (didGameEnd()) {
                alert("游戏结束！你的最终得分是: " + score + "\n按 F5 刷新页面重新开始。");
                return;
            }

            setTimeout(function onTick() {
                changingDirection = false;
                clearCanvas();
                drawFood();
                advanceSnake();
                drawSnake();

                // 递归调用 main 继续循环
                main();
            }, 100) // 100毫秒刷新一次，数字越小速度越快
        }

        // 清空画布
        function clearCanvas() {
            ctx.fillStyle = CANVAS_BACKGROUND_COLOUR;
            ctx.strokestyle = CANVAS_BORDER_COLOUR;
            ctx.fillRect(0, 0, gameCanvas.width, gameCanvas.height);
            ctx.strokeRect(0, 0, gameCanvas.width, gameCanvas.height);
        }

        // 绘制蛇
        function drawSnake() {
            snake.forEach(drawSnakePart);
        }

        // 绘制蛇的每一节
        function drawSnakePart(snakePart) {
            ctx.fillStyle = SNAKE_COLOUR;
            ctx.strokestyle = SNAKE_BORDER_COLOUR;
            ctx.fillRect(snakePart.x, snakePart.y, 10, 10);
            ctx.strokeRect(snakePart.x, snakePart.y, 10, 10);
        }

        // 移动蛇
        function advanceSnake() {
            // 创建新的头部
            const head = {x: snake[0].x + dx, y: snake[0].y + dy};
            // 将新头部加到数组最前面
            snake.unshift(head);

            const didEatFood = snake[0].x === foodX && snake[0].y === foodY;
            if (didEatFood) {
                // 如果吃到食物，分数增加，生成新食物（不移除尾部，蛇变长）
                score += 10;
                scoreElement.innerHTML = score;
                createFood();
            } else {
                // 如果没吃到，移除尾部（保持长度不变）
                snake.pop();
            }
        }

        // 改变方向
        function changeDirection(event) {
            const LEFT_KEY = 37;
            const RIGHT_KEY = 39;
            const UP_KEY = 38;
            const DOWN_KEY = 40;

            if (changingDirection) return;
            changingDirection = true;

            const keyPressed = event.keyCode;
            const goingUp = dy === -10;
            const goingDown = dy === 10;
            const goingRight = dx === 10;
            const goingLeft = dx === -10;

            if (keyPressed === LEFT_KEY && !goingRight) {
                dx = -10;
                dy = 0;
            }
            if (keyPressed === UP_KEY && !goingDown) {
                dx = 0;
                dy = -10;
            }
            if (keyPressed === RIGHT_KEY && !goingLeft) {
                dx = 10;
                dy = 0;
            }
            if (keyPressed === DOWN_KEY && !goingUp) {
                dx = 0;
                dy = 10;
            }
        }

        // 生成随机食物
        function randomTen(min, max) {
            return Math.round((Math.random() * (max-min) + min) / 10) * 10;
        }

        function createFood() {
            foodX = randomTen(0, gameCanvas.width - 10);
            foodY = randomTen(0, gameCanvas.height - 10);

            // 确保食物不会生成在蛇身上
            snake.forEach(function isFoodOnSnake(part) {
                const foodIsoNsnake = part.x == foodX && part.y == foodY;
                if (foodIsoNsnake) createFood();
            });
        }

        // 绘制食物
        function drawFood() {
            ctx.fillStyle = FOOD_COLOUR;
            ctx.strokestyle = FOOD_BORDER_COLOUR;
            ctx.fillRect(foodX, foodY, 10, 10);
            ctx.strokeRect(foodX, foodY, 10, 10);
        }

        // 检测游戏是否结束
        function didGameEnd() {
            for (let i = 4; i < snake.length; i++) {
                const didCollide = snake[i].x === snake[0].x && snake[i].y === snake[0].y
                if (didCollide) return true
            }

            const hitLeftWall = snake[0].x < 0;
            const hitRightWall = snake[0].x > gameCanvas.width - 10;
            const hitTopWall = snake[0].y < 0;
            const hitBottomWall = snake[0].y > gameCanvas.height - 10;

            return hitLeftWall || hitRightWall || hitTopWall || hitBottomWall
        }
    </script>
</body>
</html>
```

### 如何使用：

1.  **复制**上面的代码。
2.  在电脑上新建一个文本文档。
3.  将代码**粘贴**进去。
4.  将文件保存为 `snake.html` (注意后缀名是 `.html` 而不是 `.txt`)。
5.  双击这个文件，它会在你的浏览器中打开。

### 游戏操作：
*   使用键盘上的 **方向键 (↑ ↓ ← →)** 来控制蛇的移动。
*   吃到红色的方块（食物）会变长并得分。
*   撞到墙壁或撞到自己的身体，游戏结束。

没问题！我在之前的代码基础上增加了**“开始游戏”**和**“暂停/继续”**按钮，并优化了游戏逻辑，使其可以通过按钮控制。

### 更新后的完整代码

你可以直接复制下面的代码覆盖原来的文件。

```html
<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>贪吃蛇游戏 - 带控制按钮</title>
    <style>
        body {
            display: flex;
            flex-direction: column;
            justify-content: center;
            align-items: center;
            height: 100vh;
            margin: 0;
            background-color: #2c3e50;
            font-family: 'Arial', sans-serif;
            color: white;
        }

        h1 { margin-top: 0; margin-bottom: 10px; }

        #gameCanvas {
            border: 5px solid #ecf0f1;
            background-color: #34495e;
            box-shadow: 0 0 20px rgba(0,0,0,0.5);
        }

        #scoreBoard {
            font-size: 24px;
            margin-bottom: 10px;
        }

        .controls {
            margin-top: 15px;
            font-size: 14px;
            color: #bdc3c7;
            margin-bottom: 15px;
        }

        /* 按钮样式 */
        .btn-container {
            display: flex;
            gap: 15px;
        }

        button {
            padding: 10px 20px;
            font-size: 16px;
            cursor: pointer;
            border: none;
            border-radius: 5px;
            color: white;
            font-weight: bold;
            transition: background 0.3s;
        }

        #startBtn { background-color: #27ae60; }
        #startBtn:hover { background-color: #2ecc71; }

        #pauseBtn { background-color: #e67e22; }
        #pauseBtn:hover { background-color: #f39c12; }

        /* 禁用状态 */
        button:disabled {
            background-color: #95a5a6;
            cursor: not-allowed;
        }
    </style>
</head>
<body>

    <h1>贪吃蛇</h1>
    <div id="scoreBoard">得分: <span id="score">0</span></div>

    <canvas id="gameCanvas" width="400" height="400"></canvas>

    <div class="controls">使用方向键 (↑ ↓ ← →) 控制移动</div>

    <!-- 新增的按钮区域 -->
    <div class="btn-container">
        <button id="startBtn" onclick="startGame()">开始游戏</button>
        <button id="pauseBtn" onclick="togglePause()">暂停</button>
    </div>

    <script>
        const gameCanvas = document.getElementById("gameCanvas");
        const ctx = gameCanvas.getContext("2d");
        const scoreElement = document.getElementById("score");
        const startBtn = document.getElementById("startBtn");
        const pauseBtn = document.getElementById("pauseBtn");

        // 颜色配置
        const CANVAS_BORDER_COLOUR = 'black';
        const CANVAS_BACKGROUND_COLOUR = "#34495e";
        const SNAKE_COLOUR = '#2ecc71';
        const SNAKE_BORDER_COLOUR = '#27ae60';
        const FOOD_COLOUR = '#e74c3c';
        const FOOD_BORDER_COLOUR = '#c0392b';

        // 游戏变量
        let snake;
        let score;
        let dx;
        let dy;
        let foodX;
        let foodY;
        let changingDirection;
        let gameLoop; // 用于存储定时器ID
        let isGameRunning = false;
        let isPaused = false;

        // 初始化画布
        clearCanvas();

        // 开始/重置游戏
        function startGame() {
            // 如果游戏正在运行，防止重复点击
            if (isGameRunning && !isPaused) return;

            // 重置所有状态
            snake = [
                {x: 200, y: 200},
                {x: 190, y: 200},
                {x: 180, y: 200},
                {x: 170, y: 200},
                {x: 160, y: 200}
            ];
            score = 0;
            dx = 10;
            dy = 0;
            isGameRunning = true;
            isPaused = false;
            scoreElement.innerHTML = score;

            // 更新按钮状态
            startBtn.innerText = "重新开始";
            pauseBtn.innerText = "暂停";
            pauseBtn.disabled = false;

            createFood();

            // 清除之前的循环（如果有）并开始新循环
            clearTimeout(gameLoop);
            main();

            // 聚焦画布以便接收键盘事件
            gameCanvas.focus(); 
        }

        // 暂停/继续功能
        function togglePause() {
            if (!isGameRunning) return;

            if (isPaused) {
                // 继续游戏
                isPaused = false;
                pauseBtn.innerText = "暂停";
                main();
            } else {
                // 暂停游戏
                isPaused = true;
                pauseBtn.innerText = "继续";
                clearTimeout(gameLoop); // 停止循环
            }
        }

        document.addEventListener("keydown", changeDirection);

        function main() {
            if (didGameEnd()) {
                isGameRunning = false;
                pauseBtn.disabled = true;
                startBtn.innerText = "开始游戏";
                alert("游戏结束！得分: " + score);
                return;
            }

            // 如果暂停了，就不继续执行
            if (isPaused) return;

            gameLoop = setTimeout(function onTick() {
                changingDirection = false;
                clearCanvas();
                drawFood();
                advanceSnake();
                drawSnake();

                // 递归调用
                main();
            }, 100);
        }

        function clearCanvas() {
            ctx.fillStyle = CANVAS_BACKGROUND_COLOUR;
            ctx.strokestyle = CANVAS_BORDER_COLOUR;
            ctx.fillRect(0, 0, gameCanvas.width, gameCanvas.height);
            ctx.strokeRect(0, 0, gameCanvas.width, gameCanvas.height);
        }

        function drawSnake() {
            snake.forEach(drawSnakePart);
        }

        function drawSnakePart(snakePart) {
            ctx.fillStyle = SNAKE_COLOUR;
            ctx.strokestyle = SNAKE_BORDER_COLOUR;
            ctx.fillRect(snakePart.x, snakePart.y, 10, 10);
            ctx.strokeRect(snakePart.x, snakePart.y, 10, 10);
        }

        function advanceSnake() {
            const head = {x: snake[0].x + dx, y: snake[0].y + dy};
            snake.unshift(head);

            const didEatFood = snake[0].x === foodX && snake[0].y === foodY;
            if (didEatFood) {
                score += 10;
                scoreElement.innerHTML = score;
                createFood();
            } else {
                snake.pop();
            }
        }

        function changeDirection(event) {
            // 如果游戏没开始或暂停中，不允许改变方向
            if (!isGameRunning || isPaused) return;

            const LEFT_KEY = 37;
            const RIGHT_KEY = 39;
            const UP_KEY = 38;
            const DOWN_KEY = 40;

            if (changingDirection) return;
            changingDirection = true;

            const keyPressed = event.keyCode;
            const goingUp = dy === -10;
            const goingDown = dy === 10;
            const goingRight = dx === 10;
            const goingLeft = dx === -10;

            if (keyPressed === LEFT_KEY && !goingRight) {
                dx = -10;
                dy = 0;
            }
            if (keyPressed === UP_KEY && !goingDown) {
                dx = 0;
                dy = -10;
            }
            if (keyPressed === RIGHT_KEY && !goingLeft) {
                dx = 10;
                dy = 0;
            }
            if (keyPressed === DOWN_KEY && !goingUp) {
                dx = 0;
                dy = 10;
            }
        }

        function randomTen(min, max) {
            return Math.round((Math.random() * (max-min) + min) / 10) * 10;
        }

        function createFood() {
            foodX = randomTen(0, gameCanvas.width - 10);
            foodY = randomTen(0, gameCanvas.height - 10);

            snake.forEach(function isFoodOnSnake(part) {
                const foodIsoNsnake = part.x == foodX && part.y == foodY;
                if (foodIsoNsnake) createFood();
            });
        }

        function drawFood() {
            ctx.fillStyle = FOOD_COLOUR;
            ctx.strokestyle = FOOD_BORDER_COLOUR;
            ctx.fillRect(foodX, foodY, 10, 10);
            ctx.strokeRect(foodX, foodY, 10, 10);
        }

        function didGameEnd() {
            for (let i = 4; i < snake.length; i++) {
                const didCollide = snake[i].x === snake[0].x && snake[i].y === snake[0].y
                if (didCollide) return true
            }

            const hitLeftWall = snake[0].x < 0;
            const hitRightWall = snake[0].x > gameCanvas.width - 10;
            const hitTopWall = snake[0].y < 0;
            const hitBottomWall = snake[0].y > gameCanvas.height - 10;

            return hitLeftWall || hitRightWall || hitTopWall || hitBottomWall
        }
    </script>
</body>
</html>
```

### 主要修改点：

1.  **HTML**: 增加了一个 `div` 容器，里面包含两个按钮：`startBtn` (开始游戏) 和 `pauseBtn` (暂停)。
2.  **CSS**: 增加了按钮的样式，使其看起来更美观，并且有鼠标悬停效果。
3.  **JavaScript**:
    *   **`startGame()` 函数**: 现在游戏不会自动开始。点击“开始游戏”会重置分数、蛇的位置，并启动循环。如果游戏正在进行，它会变成“重新开始”。
    *   **`togglePause()` 函数**: 点击“暂停”会清除定时器（停止蛇移动），按钮文字变为“继续”。再次点击会恢复游戏。
    *   **状态管理**: 增加了 `isGameRunning` 和 `isPaused` 变量，防止在暂停时还能控制蛇的方向，或者在游戏未开始时触发逻辑。
